/** Retrieve style entries for a specific template */
export function getStylesForTemplate(templateId: string): StyleEntry[] {
  return TEMPLATE_STYLES[templateId] ?? [];
}

/** Get unique style categories for a template */
export function getStyleCategories(templateId: string): string[] {
  const styles = getStylesForTemplate(templateId);
  return [...new Set(styles.map((s) => s.category))];
}
